create table price_watches (id bigint generated always as identity primary key, email text not null, target_type text not null, target_name text not null, area text, threshold_pct numeric not null default 5, last_psf numeric, active boolean not null default true, unsubscribe_token uuid not null default gen_random_uuid(), created_at timestamptz not null default now(), last_checked_at timestamptz, last_alerted_at timestamptz); alter table price_watches enable row level security;